import argparse
import json
import os
import numpy as np
import heapq
from collections import deque
from cogniplan_env import ExplorationEnv


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n['coords'])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get('coords', nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n['coords'], dtype=float) -
                    np.array(nodes[j]['coords'], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


def first_step_index(prev, r_idx, target_j, node_to_nb):
    """Trace back from target_j to the robot neighbor index."""
    if prev[target_j] is None:
        return None
    cur = target_j
    depth = 0
    max_depth = len(prev) + 5
    while prev[cur] != r_idx and prev[cur] is not None and depth < max_depth:
        cur = prev[cur]
        depth += 1
    if prev[cur] == r_idx and cur in node_to_nb:
        return node_to_nb[cur]
    return None


class CommitPlanner:
    def __init__(self, dist_denom=3.6, reverse_penalty=0.5,
                 persist_boost=1.0, recent_penalty=0.6,
                 max_commit_steps=12):
        self.dist_denom = float(dist_denom)
        self.reverse_penalty = float(reverse_penalty)
        self.persist_boost = float(persist_boost)
        self.recent_penalty = float(recent_penalty)
        self.max_commit_steps = int(max_commit_steps)
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_pos = None
        self.target_j = None
        self.commit_steps = 0
        self.recent_nodes = deque(maxlen=15)
        self.last_nb_idx = None

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs['robot_pos'], dtype=float)
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        frontiers = obs.get('frontiers', [])

        if not neighbors:
            self.prev_pos = robot_pos
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                node_to_nb[j] = idx

        # Record current node as recent if robot is on a node
        cur_j = coord_to_idx.get(round_coord(robot_pos))
        if cur_j is not None:
            self.recent_nodes.append(cur_j)

        # Determine reverse neighbor index
        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        # Helper to pick a target and return its first-step neighbor
        def pick_target(candidate_js, force=False):
            best_score = -float('inf')
            best_j = None
            for j in candidate_js:
                if j not in node_to_nb:
                    continue
                utility = float(nodes[j].get('utility', 0.0))
                if not force and utility <= 0:
                    continue
                d = dist[j]
                if d == float('inf'):
                    continue
                score = utility / (d + self.dist_denom) if not force else 1.0 / (d + self.dist_denom)
                nb_idx = node_to_nb[j]
                if nb_idx == reverse_idx:
                    score *= self.reverse_penalty
                if j == self.target_j:
                    score *= self.persist_boost
                if j in self.recent_nodes:
                    score *= self.recent_penalty
                if score > best_score:
                    best_score = score
                    best_j = j
            return best_j

        # Check existing commitment
        if self.target_j is not None and 0 <= self.target_j < N:
            reachable = dist[self.target_j] < float('inf')
            still_good = float(nodes[self.target_j].get('utility', 0.0)) > 0
            if reachable and still_good and self.commit_steps < self.max_commit_steps:
                nb_idx = first_step_index(prev, r_idx, self.target_j, node_to_nb)
                if nb_idx is not None:
                    self.commit_steps += 1
                    self.prev_pos = robot_pos
                    self.last_nb_idx = nb_idx
                    return tuple(np.array(neighbors[nb_idx], dtype=float).tolist())
            # commitment broken
            self.target_j = None
            self.commit_steps = 0

        # Primary: nodes with positive utility
        utility_nodes = [j for j in range(N) if float(nodes[j].get('utility', 0.0)) > 0 and dist[j] < float('inf')]
        best_j = pick_target(utility_nodes)

        if best_j is None:
            # Fallback 1: nearest unvisited node
            unvisited = [j for j in range(N) if not nodes[j].get('visited', False) and dist[j] < float('inf')]
            if unvisited:
                unvisited.sort(key=lambda j: dist[j])
                best_j = pick_target(unvisited[:10], force=True)

        if best_j is None:
            # Fallback 2: node closest to any frontier
            if frontiers:
                frontier_arr = np.array(frontiers, dtype=float)
                node_coords = np.array([nodes[j]['coords'] for j in range(N)], dtype=float)
                # nearest frontier distance per node
                nf_dists = np.min(np.linalg.norm(node_coords[:, None, :] - frontier_arr[None, :, :], axis=2), axis=1)
                frontier_order = np.argsort(nf_dists)
                candidates = [int(j) for j in frontier_order[:10] if dist[j] < float('inf')]
                best_j = pick_target(candidates, force=True)

        if best_j is None and neighbors:
            # Fallback 3: farthest neighbor from previous position to avoid loops
            best_nb = 0
            best_nb_dist = -1.0
            for idx, nb in enumerate(neighbors):
                if idx == reverse_idx:
                    continue
                d = float(np.linalg.norm(np.array(nb, dtype=float) - robot_pos))
                if d > best_nb_dist:
                    best_nb_dist = d
                    best_nb = idx
            self.prev_pos = robot_pos
            self.last_nb_idx = best_nb
            return tuple(np.array(neighbors[best_nb], dtype=float).tolist())

        if best_j is not None:
            self.target_j = best_j
            self.commit_steps = 1
            nb_idx = first_step_index(prev, r_idx, best_j, node_to_nb)
            if nb_idx is None:
                # shouldn't happen since best_j is in node_to_nb
                nb_idx = 0
            self.prev_pos = robot_pos
            self.last_nb_idx = nb_idx
            return tuple(np.array(neighbors[nb_idx], dtype=float).tolist())

        self.prev_pos = robot_pos
        return None


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for _ in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done'):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    ckpt_dir = args.checkpoint
    cfg_path = os.path.join(ckpt_dir, 'planner_cfg.json')
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path) as f:
            cfg = json.load(f)
    planner = CommitPlanner(**cfg)

    # Load eval spec
    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path) as f:
            eval_config = json.load(f)
        if isinstance(eval_config, dict) and 'episodes' in eval_config:
            episodes = eval_config['episodes']
        elif isinstance(eval_config, list):
            episodes = eval_config

    # Fallback: scan maps_eval directory
    if not episodes:
        maps_dir = os.path.join(args.data_path, 'maps_eval')
        if os.path.isdir(maps_dir):
            for env_type in ['room', 'tunnel', 'outdoor']:
                subdir = os.path.join(maps_dir, env_type)
                if not os.path.isdir(subdir):
                    continue
                for fname in sorted(os.listdir(subdir)):
                    if fname.endswith('.png'):
                        episodes.append({
                            'map_path': os.path.join('maps_eval', env_type, fname),
                            'env_type': env_type
                        })

    per_episode = []
    per_type = {}
    for ep in episodes:
        map_path = os.path.join(args.data_path, ep['map_path'])
        env_type = ep.get('env_type', 'unknown')
        if not os.path.exists(map_path):
            continue
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get('success', False) else 0
        travel_distance = float(metrics.get('travel_distance', 0.0))
        explored_rate = float(metrics.get('explored_rate', 0.0))
        per_episode.append({
            'map_path': ep['map_path'],
            'env_type': env_type,
            'success': success,
            'travel_distance': travel_distance,
            'explored_rate': explored_rate
        })
        if env_type not in per_type:
            per_type[env_type] = []
        per_type[env_type].append({
            'success': success,
            'travel_distance': travel_distance,
            'explored_rate': explored_rate
        })

    total = len(per_episode)
    success_rate = sum(e['success'] for e in per_episode) / total if total else 0.0
    explored_rate = sum(e['explored_rate'] for e in per_episode) / total if total else 0.0
    succ_dists = [e['travel_distance'] for e in per_episode if e['success']]
    travel_distance = sum(succ_dists) / len(succ_dists) if succ_dists else 0.0

    per_type_out = {}
    for env_type, vals in per_type.items():
        s = sum(v['success'] for v in vals)
        n = len(vals)
        sd = [v['travel_distance'] for v in vals if v['success']]
        per_type_out[env_type] = {
            'explored_rate': sum(v['explored_rate'] for v in vals) / n,
            'travel_distance': sum(sd) / len(sd) if sd else 0.0,
            'success_rate': s / n
        }

    out = {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total
    }
    os.makedirs(os.path.dirname(args.output) or '.', exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(out, f, indent=2)


if __name__ == '__main__':
    main()
